### 3. `script.js` (Opsional, untuk interaktivitas)

```javascript
// Contoh interaktivitas sederhana: menampilkan alert saat form dikirim
const form = document.querySelector('form');
const submitButton = form.querySelector('button[type="submit"]');

submitButton.addEventListener('click', function(event) {
    // Mencegah form untuk benar-benar dikirim ke server (karena kita belum punya server)
    event.preventDefault();

    const namaInput = document.getElementById('nama');
    const emailInput = document.getElementById('email');
    const pesanInput = document.getElementById('pesan');

    const nama = namaInput.value;
    const email = emailInput.value;
    const pesan = pesanInput.value;

    if (nama && email && pesan) {
        alert(`Terima kasih, ${nama}! Pesan Anda telah diterima.`);
        // Di sini Anda bisa menambahkan logika untuk benar-benar mengirim data jika ada backend
        form.reset(); // Mengosongkan form setelah alert
    } else {
        alert('Mohon lengkapi semua kolom sebelum mengirim.');
    }
});

